class Solution:
    def maxSubArray(self, nums: list[int]) -> int:
        best = float('-inf')
        n = len(nums)
        for i in range(n):
            current = 0
            for j in range(i, n):
                current += nums[j]
                best = max(best, current)
        return best

class Solution:
    def maxSubArray(self, nums: list[int]) -> int:
        max_sum = nums[0]
        current_sum = 0
        for num in nums:
            current_sum = max(current_sum + num, num)  # extend or start fresh
            max_sum = max(max_sum, current_sum)
        return max_sum

class Solution:
    def maxSubArray(self, nums: list[int]) -> int:
        def helper(left: int, right: int) -> int:
            if left == right:
                return nums[left]

            mid = (left + right) // 2

            # Best in left half
            left_max = helper(left, mid)
            # Best in right half
            right_max = helper(mid + 1, right)

            # Best crossing mid: sum from mid going left + sum from mid+1 going right
            left_sum = float('-inf')
            current = 0
            for i in range(mid, left - 1, -1):
                current += nums[i]
                left_sum = max(left_sum, current)

            right_sum = float('-inf')
            current = 0
            for i in range(mid + 1, right + 1):
                current += nums[i]
                right_sum = max(right_sum, current)

            cross_max = left_sum + right_sum

            return max(left_max, right_max, cross_max)

        return helper(0, len(nums) - 1)

