class Solution:
    def canJump(self, nums: list[int]) -> bool:
        n = len(nums)
        memo = {}

        def can_reach_end(i: int) -> bool:
            if i >= n - 1:
                return True
            if i in memo:
                return memo[i]

            # Try all possible jumps from position i
            furthest = min(i + nums[i], n - 1)
            for next_pos in range(i + 1, furthest + 1):
                if can_reach_end(next_pos):
                    memo[i] = True
                    return True

            memo[i] = False
            return False

        return can_reach_end(0)

class Solution:
    def jump(self, nums: list[int]) -> int:
        n = len(nums)
        if n == 1:
            return 0

        dp = [float('inf')] * n
        dp[0] = 0

        for i in range(n):
            # From position i, update all reachable positions
            for j in range(1, nums[i] + 1):
                if i + j < n:
                    dp[i + j] = min(dp[i + j], dp[i] + 1)

        return dp[n - 1]

class Solution:
    def canCompleteCircuit(self, gas: list[int], cost: list[int]) -> int:
        n = len(gas)

        for start in range(n):
            tank = 0
            can_complete = True

            # Try to complete the circuit starting from 'start'
            for i in range(n):
                station = (start + i) % n
                tank += gas[station] - cost[station]
                if tank < 0:
                    can_complete = False
                    break

            if can_complete:
                return start

        return -1

class Solution:
    def canCompleteCircuit(self, gas: list[int], cost: list[int]) -> int:
        if sum(gas) < sum(cost):
            return -1
        start = 0
        tank = 0
        for i in range(len(gas)):
            tank += gas[i] - cost[i]
            if tank < 0:
                start = i + 1  # reset start
                tank = 0
        return start

