import heapq

class Solution:
    def isNStraightHand(self, hand: list[int], groupSize: int) -> bool:
        if len(hand) % groupSize != 0:
            return False

        count = Counter(hand)
        min_heap = list(count.keys())
        heapq.heapify(min_heap)

        while min_heap:
            # Start a new group with the smallest card
            first = min_heap[0]
            for i in range(groupSize):
                card = first + i
                if count[card] == 0:
                    return False  # missing card for this group
                count[card] -= 1
                if count[card] == 0:
                    # This card is exhausted; remove from heap
                    if card != min_heap[0]:
                        return False  # we can only remove the min
                    heapq.heappop(min_heap)

        return True

class Solution:
    def mergeTriplets(self, triplets: list[list[int]], target: list[int]) -> bool:
        found = [False, False, False]
        for t in triplets:
            if t[0] <= target[0] and t[1] <= target[1] and t[2] <= target[2]:
                # this triplet is 'safe' to merge
                if t[0] == target[0]:
                    found[0] = True
                if t[1] == target[1]:
                    found[1] = True
                if t[2] == target[2]:
                    found[2] = True
        return all(found)

class Solution:
    def checkValidString(self, s: str) -> bool:
        min_open = 0  # minimum possible open parens
        max_open = 0  # maximum possible open parens
        for c in s:
            if c == '(':
                min_open += 1
                max_open += 1
            elif c == ')':
                min_open -= 1
                max_open -= 1
            else:  # '*'
                min_open -= 1  # treat as ')' for min
                max_open += 1  # treat as '(' for max
            if max_open < 0:
                return False  # too many ')'
            min_open = max(min_open, 0)  # can't go negative
        return min_open == 0  # must be able to balance exactly

class Solution:
    def checkValidString(self, s: str) -> bool:
        memo = {}

        def dp(i: int, open_count: int) -> bool:
            if open_count < 0:
                return False  # more ')' than '('
            if i == len(s):
                return open_count == 0
            if (i, open_count) in memo:
                return memo[(i, open_count)]

            result = False
            if s[i] == '(':
                result = dp(i + 1, open_count + 1)
            elif s[i] == ')':
                result = dp(i + 1, open_count - 1)
            else:  # '*' — try all three
                result = (dp(i + 1, open_count + 1) or  # treat as '('
                          dp(i + 1, open_count - 1) or  # treat as ')'
                          dp(i + 1, open_count))         # treat as empty

            memo[(i, open_count)] = result
            return result

        return dp(0, 0)

class Solution:
    def checkValidString(self, s: str) -> bool:
        # Left-to-right: treat * as (
        open_count = 0
        for c in s:
            if c == '(' or c == '*':
                open_count += 1
            else:  # ')'
                open_count -= 1
            if open_count < 0:
                return False  # too many ')'

        # Right-to-left: treat * as )
        close_count = 0
        for c in reversed(s):
            if c == ')' or c == '*':
                close_count += 1
            else:  # '('
                close_count -= 1
            if close_count < 0:
                return False  # too many '('

        return True

def findMinArrowShots(points):
    points.sort(key=lambda x:(x[0],x[1]))
    numArrows, index = 0, 0
    while index<len(points):
        nextBalloonToPickEnd = points[index][1]
        while index<len(points) and points[index][0]<=nextBalloonToPickEnd:
            nextBalloonToPickEnd = min(nextBalloonToPickEnd, points[index][1])
            index += 1
        numArrows += 1
    return numArrows

