from collections import deque
class Solution:
    def jump(self, nums):
        queue, visited, n = deque([(0,0)]), set([0]), len(nums)
        if n==1: return 0
        while queue:
            index, stepsSoFar = queue.popleft()
            for neigh in range(index+1, index+nums[index]+1):
                if neigh==n-1:
                    return stepsSoFar+1
                if neigh not in visited:
                    visited.add(neigh)
                    queue.append((neigh, stepsSoFar+1))

